
-- VISTA BILANCIO SINTETICO

IF  EXISTS (SELECT * FROM sys.views WHERE object_id = OBJECT_ID(N'[dbo].[BILANCIO_SINTETICO]'))
	DROP VIEW [dbo].[BILANCIO_SINTETICO]
GO

CREATE VIEW [dbo].[BILANCIO_SINTETICO]  
AS
SELECT * FROM (
	SELECT
		CON_POSBIL AS TIPO,
		CON_ANNO AS ANNO,
		CON_CONTO AS CONTO,
		CON_DESCR AS DESCRIZIONE,
		CON_DA01 -CON_AV01 +PRE_DA01 -PRE_AV01 AS SALDO_GEN,
		CON_DA01+CON_DA02 -CON_AV01-CON_AV02 + PRE_DA01+PRE_DA02 -PRE_AV01-PRE_AV02 AS SALDO_FEB,
		CON_DA01+CON_DA02+CON_DA03 -CON_AV01-CON_AV02-CON_AV03 +PRE_DA01+PRE_DA02+PRE_DA03 -PRE_AV01-PRE_AV02-PRE_AV03 AS SALDO_MAR,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04 -CON_AV01-CON_AV02-CON_AV03-CON_AV04 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04 AS SALDO_APR,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05 AS SALDO_MAG,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06 AS SALDO_GIU,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07 AS SALDO_LUG,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07+CON_DA08 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07-CON_AV08 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07+PRE_DA08 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07-PRE_AV08 AS SALDO_AGO,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07+CON_DA08+CON_DA09 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07-CON_AV08-CON_AV09 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07+PRE_DA08+PRE_DA09 - PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07-PRE_AV08-PRE_AV09 AS SALDO_SET,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07+CON_DA08+CON_DA09+CON_DA10 -CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07-CON_AV08-CON_AV09-CON_AV10 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07+PRE_DA08+PRE_DA09+PRE_DA10 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07-PRE_AV08-PRE_AV09-PRE_AV10 AS SALDO_OTT,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07+CON_DA08+CON_DA09+CON_DA10+CON_DA11 - CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07-CON_AV08-CON_AV09-CON_AV10-CON_AV11 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07+PRE_DA08+PRE_DA09+PRE_DA10+PRE_DA11 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07-PRE_AV08-PRE_AV09-PRE_AV10-PRE_AV11 AS SALDO_NOV,
		CON_DA01+CON_DA02+CON_DA03+CON_DA04+CON_DA05+CON_DA06+CON_DA07+CON_DA08+CON_DA09+CON_DA10+CON_DA11+CON_DA12 - CON_AV01-CON_AV02-CON_AV03-CON_AV04-CON_AV05-CON_AV06-CON_AV07-CON_AV08-CON_AV09-CON_AV10-CON_AV11-CON_AV12 +PRE_DA01+PRE_DA02+PRE_DA03+PRE_DA04+PRE_DA05+PRE_DA06+PRE_DA07+PRE_DA08+PRE_DA09+PRE_DA10+PRE_DA11+PRE_DA12 -PRE_AV01-PRE_AV02-PRE_AV03-PRE_AV04-PRE_AV05-PRE_AV06-PRE_AV07-PRE_AV08-PRE_AV09-PRE_AV10-PRE_AV11-PRE_AV12 AS SALDO_DIC,
		CON_IMP_D-CON_IMP_A+PRE_IMP_D-PRE_IMP_A AS SALDO_ANNO
	FROM CONTI AS CC
	WHERE ((LEN(CON_CONTO) > (SELECT TOP 1 AZI_SOTTOG FROM U_AZI_AN) AND CON_TIPOCO NOT IN ('C','F')) OR CON_CONTO IN ('2011','2012','2010','1031','1032','1030'))
	) AS MAIN
WHERE SALDO_GEN <> 0 OR SALDO_FEB <> 0 OR SALDO_MAR <> 0 OR SALDO_APR <> 0 OR SALDO_MAG <> 0 OR SALDO_GIU <> 0 OR SALDO_LUG <> 0 OR SALDO_AGO <> 0 OR SALDO_SET <> 0 OR SALDO_OTT <> 0 OR SALDO_NOV <> 0 OR SALDO_DIC <> 0
GO
